div.kanban-board.d-flex.flex-nowrap
  .lane.d-flex.flex-column(role=\"list\" aria-label=\"TO DO\")
    h5.lane-title TO DO
    div.user-group(v-for=\"user in tickets.TODO\" :key=\"user.id\")
      div.card(:class=\"{'high-priority': card.priorityIcon === 'flag-fill'}\" v-for=\"card in user.cards\" :key=\"card.id\")
        .card-header
          .title {{ card.title }}
        .card-meta.d-flex.align-items-center.mt-2
