          .assignee-name.ms-2.text-muted {{ card.assignee }}
        .card-details.d-flex.justify-content-between.align-items-center.mt-2
          .badge.bg-secondary.text-nowrap {{ card.epic }}
          .ticket-info.d-flex.align-items-center
            i.bi(:class=\"'bi-' + card.typeIcon\" aria-label=\"'Ticket type: ' + card.typeIcon\")
              span.visually-hidden {{ card.typeIcon }}
            span.ms-1.code {{ card.code }}
            i.bi(:class=\"'bi-' + card.priorityIcon\" aria-label=\"'Priority: ' + card.priorityIcon\")
