css:
.kanban-board { overflow-x: auto; padding: 1rem; background: #fafafa; height: 100vh; }
.lane { min-width: 250px; margin-right: 1rem; border-right: 1px solid #ddd; padding-bottom: 1rem; padding-right: 1rem; background: #f9f9f9; }
.lane:nth-child(even) { background: #e9f7ff; }
.lane-title { font-weight: 600; font-size: 1.1rem; margin-bottom: 0.75rem; color: #333; }
.card { background: #e8f5e9; border-radius: 0.375rem; padding: 0.75rem; margin-bottom: 1rem; box-shadow: 0 1px 3px rgb(0 0 0 / 0.1); transition: background 0.3s; }
.card.high-priority { background: #ffebee; }
.card-header .title { font-weight: 500; font-size: 1rem; color: #000; }
.card-meta { margin-top: 0.5rem; }
.card-details { font-size: 0.85rem; color: #555; margin-top: 0.5rem; }
.ticket-info i { font-size: 1rem; color: #007bff; }
.ticket-info .code { font-family: monospace; font-weight: 6:0; margin-left: 0.25rem; }
.bordered-avatar { border: 2px solid #ccc; }
.assignee-name { font-size: 0.9rem; color: #555; }
.visually-hidden { position: absolute; width: 1px; height: 1px; padding: 0; margin: -1px; overflow: hidden; clip: rect(0,0,0,0); border: 0; }
.ticket-info i.bi-flag-fill { color: #ff4d4f; }
